import base64, os, psycopg

def write(path, b64):
    import os as _os
    _os.makedirs(_os.path.dirname(path) or '.', exist_ok=True)
    open(path,'wb').write(base64.b64decode(b64))
    print('  wrote ' + path)

FILES = {
    'pacing/calendar_live_data.py': '',
    'pacing/calendar.py': '',
    'scripts/cron_dispatch.py': '',
    'db/migrations/009_actual_revenue.sql': '',
}
for path, b64 in FILES.items():
    write(path, b64)

print('Running migration 009...')
try:
    with psycopg.connect(os.environ['DATABASE_URL']) as conn:
        conn.execute(open('db/migrations/009_actual_revenue.sql').read())
        conn.commit()
    print('  migration 009 applied')
except Exception as e:
    print('  note: ' + str(e))

print('''Done.
Regenerate May calendar with live data:
  python3 -c "from pacing.calendar import run_monthly; run_monthly()"

Calendar will auto-generate for June on May 24th at 9am ET.
''')
